```javascript
let mocha = require('mocha');
let assert = require('assert');
let pull_stream = require('pull-stream');

describe('test pull_stream', function() {
    // Helper functions for testing
    function createSource(data) {
        let index = 0;
        return function(end, cb) {
            if (end || index >= data.length) {
                return cb(true);
            }
            cb(null, data[index++]);
        };
    }

    function createTransform(fn) {
        return function(read) {
            return function(end, cb) {
                read(end, function(end, data) {
                    if (end) return cb(end);
                    cb(null, fn(data));
                });
            };
        };
    }

    function createSink(callback) {
        let results = [];
        return function(read) {
            function next() {
                read(null, function(end, data) {
                    if (end === true) {
                        callback(null, results);
                        return;
                    }
                    if (end) {
                        callback(end);
                        return;
                    }
                    results.push(data);
                    next();
                });
            }
            next();
        };
    }

    it('should handle basic source-sink connection', function(done) {
        const source = createSource([1, 2, 3]);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [1, 2, 3]);
            done();
        });

        pull_stream(source, sink);
    });

    it('should handle source-transform-sink pipeline', function(done) {
        const source = createSource([1, 2, 3]);
        const transform = createTransform(x => x * 2);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [2, 4, 6]);
            done();
        });

        pull_stream(source, transform, sink);
    });

    it('should handle multiple transforms', function(done) {
        const source = createSource([1, 2, 3]);
        const double = createTransform(x => x * 2);
        const addOne = createTransform(x => x + 1);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [3, 5, 7]); // (1*2)+1, (2*2)+1, (3*2)+1
            done();
        });

        pull_stream(source, double, addOne, sink);
    });

    it('should support partial application with single function', function(done) {
        const transform = createTransform(x => x * 3);
        const partialPull = pull_stream(transform);

        assert.strictEqual(typeof partialPull, 'function');

        const source = createSource([2, 4]);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [6, 12]);
            done();
        });

        partialPull(pull_stream(source, sink));
    });

    it('should support partial application with multiple functions', function(done) {
        const double = createTransform(x => x * 2);
        const triple = createTransform(x => x * 3);
        const partialPull = pull_stream(double, triple);

        assert.strictEqual(typeof partialPull, 'function');

        const source = createSource([1, 2]);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [6, 12]); // 1*2*3, 2*2*3
            done();
        });

        partialPull(pull_stream(source, sink));
    });

    it('should throw error when partial sink called multiple times', function() {
        const transform = createTransform(x => x);
        const partialPull = pull_stream(transform);
        const source = createSource([1]);

        // First call should work
        partialPull(source);

        // Second call should throw
        assert.throws(() => {
            partialPull(source);
        }, TypeError, "partial sink should only be called once!");
    });

    it('should handle objects with source property', function(done) {
        const sourceObj = {
            source: createSource([5, 10])
        };

        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [5, 10]);
            done();
        });

        pull_stream(sourceObj, sink);
    });

    it('should handle objects with sink and source properties', function(done) {
        let sinkResults = [];
        const throughObj = {
            sink: function(read) {
                function next() {
                    read(null, function(end, data) {
                        if (end) return;
                        sinkResults.push(data);
                        next();
                    });
                }
                next();
            },
            source: createSource([100, 200])
        };

        const source = createSource([1, 2]);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [100, 200]); // from throughObj.source
            assert.deepStrictEqual(sinkResults, [1, 2]); // consumed by throughObj.sink
            done();
        });

        pull_stream(source, throughObj, sink);
    });

    it('should handle empty pipeline', function() {
        const source = createSource([1, 2, 3]);
        const result = pull_stream(source);
        assert.strictEqual(result, source);
    });

    it('should handle more than 4 arguments (default case)', function(done) {
        const source = createSource([1]);
        const t1 = createTransform(x => x + 1);
        const t2 = createTransform(x => x + 1);
        const t3 = createTransform(x => x + 1);
        const t4 = createTransform(x => x + 1);
        const t5 = createTransform(x => x + 1);

        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [6]); // 1+1+1+1+1+1
            done();
        });

        pull_stream(source, t1, t2, t3, t4, t5, sink);
    });
});
